mapper.select:
SELECT DATE_FORMAT(m.record_time, '%Y-%m-%d') AS label, IFNULL(SUM(m.solar_generation_kwh), 0) AS generationKwh, IFNULL(SUM(m.charged_energy_kwh), 0) AS chargedKwh, IFNULL(SUM(m.used_energy_kwh), 0) AS usedKwh, IFNULL(SUM(m.saved_cost), 0) AS savedCost FROM monitoring m JOIN ess_device d ON m.device_id = d.device_id WHERE d.member_id = #{memberId} AND m.record_time >= STR_TO_DATE(#{startDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{endDate}, '%Y-%m-%d'), INTERVAL 1 DAY)
AND m.device_id = #{deviceId}
GROUP BY DATE_FORMAT(m.record_time, '%Y-%m-%d') ORDER BY label ASC

SELECT d.device_name AS label, IFNULL(SUM(m.solar_generation_kwh), 0) AS generationKwh, IFNULL(SUM(m.charged_energy_kwh), 0) AS chargedKwh, IFNULL(SUM(m.used_energy_kwh), 0) AS usedKwh, IFNULL(SUM(m.saved_cost), 0) AS savedCost FROM ess_device d LEFT JOIN monitoring m ON d.device_id = m.device_id AND m.record_time >= STR_TO_DATE(#{startDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{endDate}, '%Y-%m-%d'), INTERVAL 1 DAY) WHERE d.member_id = #{memberId}
AND d.device_id = #{deviceId}
GROUP BY d.device_id, d.device_name ORDER BY generationKwh DESC

SELECT DATE_FORMAT(e.log_date, '%Y-%m-%d') AS label, IFNULL(SUM(e.daily_kwh), 0) AS dailyKwh, IFNULL(SUM(e.monthly_kwh), 0) AS monthlyKwh, IFNULL(SUM(e.cost), 0) AS cost, IFNULL(AVG(e.efficiency), 0) AS efficiency FROM energy_log e JOIN ess_device d ON e.device_id = d.device_id WHERE d.member_id = #{memberId} AND e.log_date >= STR_TO_DATE(#{startDate}, '%Y-%m-%d') AND e.log_date <= STR_TO_DATE(#{endDate}, '%Y-%m-%d')
AND e.device_id = #{deviceId}
GROUP BY DATE_FORMAT(e.log_date, '%Y-%m-%d') ORDER BY label ASC
